1	type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	type Step = { op: "quote"; items: Item[] };
8	type Customer = { yearsWithMHPCO: number };
9	type Scenario = { customer: Customer; steps: Step[] };
10	type QuoteResult = { premium: number };
11	
12	const PROCESSING_FEE = 5;
13	const FIRST_INSURANCE_RATE = 0.1;
14	const CURSE_RATE = 0.5;
15	const HIGH_ENCHANTMENT_RATE = 0.3;
16	const HIGH_ENCHANTMENT_THRESHOLD = 5;
17	const LOYALTY_RATE = 0.2;
18	const LOYALTY_THRESHOLD = 2;
19	const FOLLOWUP_RATE = 0.15;
20	const COMPONENT_BASE_PREMIUM = 25;
21	const BLOCK_SIZE = 3;
22	const BLOCK_BASE_PREMIUM = 60;
23	
24	const BASE_PREMIUMS: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	};
30	
31	const isComponent = (item: Item): boolean => BASE_PREMIUMS[item.type] === undefined;
32	
33	const componentGroupBase = (count: number): number =>
34	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * COMPONENT_BASE_PREMIUM;
35	
36	const countByType = (items: Item[]): Map<string, number> =>
37	  items.reduce(
38	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
39	    new Map<string, number>(),
40	  );
41	
42	// Returns base premium attributed to a single main item (not components).
43	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];
44	
45	// Components are priced per group with block discount.
46	const componentsBaseTotal = (components: Item[]): number =>
47	  [...countByType(components).values()].reduce(
48	    (sum, count) => sum + componentGroupBase(count),
49	    0,
50	  );
51	
52	// Base premium of the whole policy (raw, no item modifiers).
53	const policyBase = (items: Item[]): number => {
54	  const mainBase = items.filter((i) => !isComponent(i)).reduce((sum, i) => sum + itemBasePremium(i), 0);
55	  const compBase = componentsBaseTotal(items.filter(isComponent));
56	  return mainBase + compBase;
57	};
58	
59	const isCursed = (item: Item): boolean => item.cursed === true;
60	const isHighlyEnchanted = (item: Item): boolean =>
61	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
62	
63	// Surcharges that apply to a single item's base premium (cursed, high enchantment).
64	const itemSurcharge = (item: Item): number => {
65	  if (isComponent(item)) return 0;
66	  const base = itemBasePremium(item);
67	  const rate = (isCursed(item) ? CURSE_RATE : 0) + (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
68	  return base * rate;
69	};
70	
71	const itemSurchargesTotal = (items: Item[]): number =>
72	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
73	
74	const isLoyal = (customer: Customer): boolean => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD;
75	
76	const loyaltyDiscount = (base: number, customer: Customer): number =>
77	  isLoyal(customer) ? base * LOYALTY_RATE : 0;
78	
79	const quoteStep = (step: Step, customer: Customer, quoteIndex: number): QuoteResult => {
80	  const base = policyBase(step.items);
81	  const surcharges = itemSurchargesTotal(step.items);
82	  const firstInsurance = base * FIRST_INSURANCE_RATE;
83	  const loyalty = loyaltyDiscount(base, customer);
84	  const followup = quoteIndex > 0 ? base * FOLLOWUP_RATE : 0;
85	  const premium = Math.ceil(base + surcharges + firstInsurance - loyalty - followup) + PROCESSING_FEE;
86	  return { premium };
87	};
88	
89	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
90	  let quoteIndex = 0;
91	  const results = scenario.steps.map((step) => {
92	    const r = quoteStep(step, scenario.customer, quoteIndex);
93	    quoteIndex += 1;
94	    return r;
95	  });
96	  return { results };
97	};
